mapper.select:
SELECT l.category_id, COUNT(*) AS resource_count
FROM info_resource_category_link l
JOIN info_resource r ON r.resource_id = l.resource_id
WHERE r.status = '0'
  AND r.del_flag = '0'

    AND (r.title LIKE CONCAT('%', #{keyword}, '%')
        OR r.description LIKE CONCAT('%', #{keyword}, '%')
        OR r.original_name LIKE CONCAT('%', #{keyword}, '%'))


    AND r.preview_type = #{previewType}


    AND r.create_time >= #{uploadedSince}


    AND r.file_size >= #{minFileSize}


    AND r.file_size < #{maxFileSize}

GROUP BY l.category_id
